+fn build_capture_smoke_command(
+    current_exe: &PathBuf,
+    args: &DoctorArgs,
+    run_name: &str,
+    dry_run: bool,
+) -> Command {
+    let mut command = Command::new(current_exe);
+    command
+        .arg("capture")
+        .arg("--profile")
+        .arg("analytics-empty")
+        .arg("--app-command")
+        .arg(&args.app_command)
+        .arg("--project-dir")
+        .arg(&args.project_dir)
+        .arg("--run-root")
+        .arg(&args.run_root)
+        .arg("--run-name")
+        .arg(run_name);
+
+    if dry_run {
+        command.arg("--dry-run");
+    } else {
+        command
+            .arg("--boot-sleep")
+            .arg("2")
+            .arg("--keys")
+            .arg("1,sleep:2,?,sleep:2,q")
+            .arg("--snapshot-second")
+            .arg("4");
+    }
+
+    if let Some(binary) = &args.binary {
+        command.arg("--binary").arg(binary);
+    }
+
+    command.stdout(Stdio::null()).stderr(Stdio::null());
+
+    command
+}
