+  tape_path="${1:-}"
+  if [[ -n "$tape_path" ]]; then
+    run_dir="$(dirname "$tape_path")"
+    suite_dir="$(dirname "$run_dir")"
+    mkdir -p "$suite_dir/report.json" "$suite_dir/index.html"
